import { Injectable } from "@angular/core";
import { AngularFirestore, AngularFirestoreCollection } from "@angular/fire/firestore";
import { throwError } from "rxjs";
import { map } from "rxjs/internal/operators/map";
import firebase from 'firebase';
import { AuthService, User } from "../auth/auth.service";

@Injectable({
    providedIn: 'root'
  })
  
export class UserService {
  collectionReference: AngularFirestoreCollection;

  constructor(private angularFirestore: AngularFirestore) {
    this.collectionReference = angularFirestore.collection("users");
  }
  
  public getUser(id) {
    return this.collectionReference.doc<User>(id).valueChanges();
  }

  public createUser(user: User) {
    return this.collectionReference.doc(user.id).set(user);
  }

  public updateUser(user: User) {
    return this.collectionReference.doc(user.id).update({...user});
  }

  public deleteUser(user: User) {
    this.collectionReference.doc(user.id).delete();
  }

  public getAllAdminUsers() {
    return this.collectionReference.snapshotChanges().pipe(
        map(changes => {
        return changes.map(element => {
          return ({id: element.payload.doc.id, ...element.payload.doc.data()} as User);
        }).filter(element => element.role === 'admin');
        }
      )
    );
  }

  getUserDoc(id: string) {
    return this.collectionReference.doc(id);
  }

  async addBrandToUser(brandId: string, uid: string) {
    return this.getUserDoc(uid).update({adminBrands: firebase.firestore.FieldValue.arrayUnion(brandId)});
  }

  async removeBrandFromUser(brandId: string, uid: string) {
    return this.getUserDoc(uid).update({adminBrands: firebase.firestore.FieldValue.arrayRemove(brandId)});
  }

  private formatErrors(error: any) {
    return throwError(error.error);
  }
}