import { Component, OnInit, ViewChild } from '@angular/core';
import { MatDialog } from '@angular/material/dialog';
import { MatPaginator, PageEvent } from '@angular/material/paginator';
import { MatTableDataSource } from '@angular/material/table';
import { Brand, BrandService } from 'src/app/api/brand/brand.service';
import { BrandPopUpComponent } from './brand-pop-up/brand-pop-up.component';

@Component({
  selector: 'app-brands',
  templateUrl: './brands.component.html',
  styleUrls: ['./brands.component.scss'],
})
export class BrandsComponent implements OnInit {
  displayedColumns: string[] = ['position', 'brandname', 'action'];
  dataSource: MatTableDataSource<Brand> = null;
  elementData: Brand[] = [];
  pageEvent: PageEvent;
  searchString: string;

  @ViewChild(MatPaginator) paginator: MatPaginator;
  constructor(private api: BrandService, private  dialogRef : MatDialog) {}
  
  ngOnInit(): void {
    this.getBrands();
  }

  searchBrand() {
    //Filters through the list of all users and
    //only shows those that match the search String
    var data: Brand[] = this.elementData.filter((brand) => {
      var brandName = brand.name.toLowerCase();
      var search = this.searchString.toLowerCase();

      return brandName.includes(search);
    });
    //Refresh the table and Pagination after the searching
    this.dataSource = new MatTableDataSource<Brand>(data);
    this.changePagination();
  }

  // searchBrand() {}
  changePagination() {
    //Set the paginator
    this.dataSource.paginator = this.paginator;
  }

  addBrand() {
    this.dialogRef.open(BrandPopUpComponent).afterClosed().subscribe((result) => {
      if (result) {
        this.api.createBrand(result).then(brand => {
          this.elementData.push(brand);
          this.dataSource = new MatTableDataSource<Brand>(this.elementData);
          this.changePagination();
        });
      }
    });
  }

  editBrand(brand: Brand) {
    console.log(brand);
    this.dialogRef.open(BrandPopUpComponent,  {
      data: { 
        name: brand.name
      }
    }).afterClosed().subscribe((result) => {
      if (result) {
        this.api.editBrand({...brand, name: result});
        const index = this.elementData.indexOf(brand);
        this.elementData[index] = {...brand, name: result};
        this.dataSource = new MatTableDataSource<Brand>(this.elementData);
        this.changePagination();
      }
    });
  }

  getBrands() {
    this.api.getBrands().subscribe((brandList) => {
      this.elementData = brandList;
      this.dataSource = new MatTableDataSource<Brand>(this.elementData);
      this.changePagination();
    });
  }
}
